1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	
11	type Item = { type: string; cursed?: boolean; enchantment?: number };
12	type Customer = { years: number };
13	type Step = { type: string; items: Item[]; customer?: Customer };
14	
15	const BLOCK_OF_3_PRICE = 60;
16	
17	const COMPONENT_TYPES = ["rune", "moonstone"];
18	
19	function countByType(items: Item[]): Record<string, number> {
20	  const counts: Record<string, number> = {};
21	  for (const item of items) {
22	    counts[item.type] = (counts[item.type] ?? 0) + 1;
23	  }
24	  return counts;
25	}
26	
27	function priceForType(type: string, count: number): number {
28	  if (COMPONENT_TYPES.includes(type) && count === 3) {
29	    return BLOCK_OF_3_PRICE;
30	  }
31	  return count * BASE_PREMIUM_BY_TYPE[type];
32	}
33	
34	function isHighlyEnchanted(item: Item): boolean {
35	  return (item.enchantment ?? 0) >= 5;
36	}
37	
38	function hasItemModifier(item: Item): boolean {
39	  return Boolean(item.cursed) || isHighlyEnchanted(item);
40	}
41	
42	const CURSE_SURCHARGE = 0.5;
43	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
44	
45	function itemPremium(item: Item): number {
46	  const base = BASE_PREMIUM_BY_TYPE[item.type];
47	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE : 0;
48	  const enchantmentSurcharge = isHighlyEnchanted(item)
49	    ? base * HIGH_ENCHANTMENT_SURCHARGE
50	    : 0;
51	  return base + curseSurcharge + enchantmentSurcharge;
52	}
53	
54	function modifiedPremium(items: Item[]): number {
55	  return items
56	    .filter(hasItemModifier)
57	    .reduce((total, item) => total + itemPremium(item), 0);
58	}
59	
60	function plainPremium(items: Item[]): number {
61	  const counts = countByType(items.filter((item) => !hasItemModifier(item)));
62	  return Object.entries(counts).reduce(
63	    (total, [type, count]) => total + priceForType(type, count),
64	    0,
65	  );
66	}
67	
68	function basePremium(items: Item[]): number {
69	  return modifiedPremium(items) + plainPremium(items);
70	}
71	
72	const LOYALTY_DISCOUNT = 0.2;
73	const LOYALTY_MIN_YEARS = 2;
74	const FIRST_INSURANCE_SURCHARGE = 0.1;
75	const FOLLOW_UP_DISCOUNT = 0.15;
76	
77	function isLoyal(customer: Customer): boolean {
78	  return customer.years >= LOYALTY_MIN_YEARS;
79	}
80	
81	function policyPremium(step: Step, isFollowUp: boolean): number {
82	  const base = basePremium(step.items);
83	  if (step.customer === undefined) {
84	    return base;
85	  }
86	  const loyaltyDiscount = isLoyal(step.customer) ? LOYALTY_DISCOUNT : 0;
87	  const followUpDiscount = isFollowUp ? FOLLOW_UP_DISCOUNT : 0;
88	  const netModifierRate =
89	    FIRST_INSURANCE_SURCHARGE - loyaltyDiscount - followUpDiscount;
90	  return base + base * netModifierRate;
91	}
92	
93	export function runScenario(steps: Step[]): unknown[] {
94	  return steps.map((step, index) => {
95	    const isFollowUp = steps
96	      .slice(0, index)
97	      .some((prior) => prior.type === "quote");
98	    return {
99	      premium: Math.ceil(PROCESSING_FEE + policyPremium(step, isFollowUp)),
100	    };
101	  });
102	}
